const expected = $env.NEFALIX_INTERNAL_KEY || '';
const headers = $json.headers || {};
const got = headers['x-nefalix-internal-key'] || headers['X-Nefalix-Internal-Key'] || '';
if (!expected || got !== expected) {
  throw new Error('Unauthorized');
}

const input = $json.body ?? $json;
const method = String(input.method || 'GET').toUpperCase();
const table = String(input.table || '').trim();
const query = String(input.query || '').replace(/^\?/, '');
const body = input.body;
const prefer = input.prefer || 'return=representation';

if (!table) throw new Error('table gerekli');
if (!['GET', 'POST', 'PATCH', 'DELETE'].includes(method)) throw new Error('Geçersiz method');

const sbBase = ($env.SUPABASE_URL || 'http://host.docker.internal:54321').replace(/\/$/, '');
const sbKey = $env.SUPABASE_SERVICE_ROLE_KEY;
if (!sbKey) throw new Error('SUPABASE_SERVICE_ROLE_KEY eksik');

const sbH = {
  apikey: sbKey,
  Authorization: `Bearer ${sbKey}`,
  'Content-Type': 'application/json',
  Prefer: prefer,
};

const url = `${sbBase}/rest/v1/${table}${query ? `?${query}` : ''}`;
const data = await this.helpers.httpRequest({
  method,
  url,
  headers: sbH,
  body: body != null ? body : undefined,
  json: true,
});

return [{ json: { ok: true, data } }];
